import{_ as a,o,c as r,ak as i}from"./chunks/framework.xMnnZPAZ.js";const m=JSON.parse('{"title":"RdpClientConfiguration","description":"","frontmatter":{},"headers":[],"relativePath":"api/reference/royalapps-community-rdp-winforms-configuration-rdpclientconfiguration.md","filePath":"api/reference/royalapps-community-rdp-winforms-configuration-rdpclientconfiguration.md"}'),n={name:"api/reference/royalapps-community-rdp-winforms-configuration-rdpclientconfiguration.md"};function t(s,e,l,d,c,p){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="rdpclientconfiguration" tabindex="-1"><code>RdpClientConfiguration</code> <a class="header-anchor" href="#rdpclientconfiguration" aria-label="Permalink to “RdpClientConfiguration”">​</a></h1><p>The remote desktop client configuration.</p><h2 id="type" tabindex="-1">Type <a class="header-anchor" href="#type" aria-label="Permalink to “Type”">​</a></h2><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RoyalApps.Community.Rdp.WinForms.Configuration.RdpClientConfiguration</span></span></code></pre></div><h2 id="used-by" tabindex="-1">Used By <a class="header-anchor" href="#used-by" aria-label="Permalink to “Used By”">​</a></h2><ul><li><a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-rdpcontrol">RdpControl</a></li></ul><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><h3 id="clientversion-int" tabindex="-1"><code>ClientVersion</code> (<code>int</code>) <a class="header-anchor" href="#clientversion-int" aria-label="Permalink to “ClientVersion (int)”">​</a></h3><p>The client version to use. By default (value is 0) the highest available client will be used.</p><h3 id="logenabled-bool" tabindex="-1"><code>LogEnabled</code> (<code>bool</code>) <a class="header-anchor" href="#logenabled-bool" aria-label="Permalink to “LogEnabled (bool)”">​</a></h3><p>When <code>true</code>, MsRdpEx logging is enabled and written to <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-rdpclientconfiguration">RdpClientConfiguration.LogFilePath</a>.</p><h3 id="logfilepath-string" tabindex="-1"><code>LogFilePath</code> (<code>string</code>) <a class="header-anchor" href="#logfilepath-string" aria-label="Permalink to “LogFilePath (string)”">​</a></h3><p>Gets or sets the MsRdpEx log file path used when <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-rdpclientconfiguration">RdpClientConfiguration.LogEnabled</a> is enabled.</p><h3 id="loglevel-string" tabindex="-1"><code>LogLevel</code> (<code>string</code>) <a class="header-anchor" href="#loglevel-string" aria-label="Permalink to “LogLevel (string)”">​</a></h3><p>Gets or sets the MsRdpEx log level, for example <code>TRACE</code>, <code>DEBUG</code>, <code>INFO</code>, <code>WARN</code>, <code>ERROR</code>, <code>FATAL</code>, or <code>OFF</code>.</p><h3 id="msrdcpath-string" tabindex="-1"><code>MsRdcPath</code> (<code>string</code>?) <a class="header-anchor" href="#msrdcpath-string" aria-label="Permalink to “MsRdcPath (string?)”">​</a></h3><p>Gets or sets the directory that is probed first for Microsoft Remote Desktop Client files such as <code>rdclientax.dll</code>.</p><h3 id="plugindlls-string-↗" tabindex="-1"><code>PluginDlls</code> (<code>string</code>?) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscadvancedsettings-plugindlls" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#plugindlls-string-↗" aria-label="Permalink to “PluginDlls (string?) ↗”">​</a></h3><p>Specifies the names of virtual channel client DLLs to be loaded. Virtual channel client DLLs are also referred to as Plug-in DLLs. Comma-separated list of the names of the virtual channel client DLLs to be loaded. The DLL names must contain only alphanumeric characters.</p><h3 id="port-int-↗" tabindex="-1"><code>Port</code> (<code>int</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-rdpport" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#port-int-↗" aria-label="Permalink to “Port (int) ↗”">​</a></h3><p>Specifies the connection port. The default value is 3389.</p><h3 id="server-string-↗" tabindex="-1"><code>Server</code> (<code>string</code>?) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscax-server" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#server-string-↗" aria-label="Permalink to “Server (string?) ↗”">​</a></h3><p>Specifies the name of the server to which the current control is connected. The new server name. This parameter can be a DNS name or IP address. This property must be set before calling the Connect method. It is the only property that must be set before connecting.</p><h3 id="sessionmode-rdpsessionmode" tabindex="-1"><code>SessionMode</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-rdpsessionmode">RdpSessionMode</a>) <a class="header-anchor" href="#sessionmode-rdpsessionmode" aria-label="Permalink to “SessionMode (RdpSessionMode)”">​</a></h3><p>Selects whether the connection should be hosted inside the control or by an external client process.</p><h3 id="usemsrdc-bool" tabindex="-1"><code>UseMsRdc</code> (<code>bool</code>) <a class="header-anchor" href="#usemsrdc-bool" aria-label="Permalink to “UseMsRdc (bool)”">​</a></h3><p>When <code>true</code>, the Microsoft Remote Desktop Client is used when available instead of the legacy MSTSC ActiveX control.</p><p><a href="./../">Back to API index</a></p>',28)])])}const f=a(n,[["render",t]]);export{m as __pageData,f as default};
